<script setup lang="ts">import{onMounted,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{api}from'../api/client';import type{Book}from'../types/book';const books=ref<Book[]>([]),loading=ref(true);async function load(){loading.value=true;try{books.value=(await api.get<Book[]>('/books/trash')).data}finally{loading.value=false}}async function restore(book:Book){await ElMessageBox.confirm(`恢复“${book.title}”到书库？`,'恢复书籍');await api.post(`/books/${book.id}/restore`);ElMessage.success('书籍已恢复');await load()}onMounted(load)</script>
<template><section v-loading="loading"><h1>回收站</h1><el-empty v-if="!loading&&!books.length" description="回收站为空"/><el-table v-else :data="books"><el-table-column prop="title" label="书名"/><el-table-column label="作者"><template #default="s">{{s.row.authors.map((a:any)=>a.name).join('、')||'-'}}</template></el-table-column><el-table-column prop="deleted_at" label="删除时间"/><el-table-column width="100" label="操作"><template #default="s"><el-button link type="primary" @click="restore(s.row)">恢复</el-button></template></el-table-column></el-table></section></template>
